def add(numbers: str) -> int:
    if not numbers:
        return 0
    # Replace newlines with commas for uniform splitting
    numbers = numbers.replace('\n', ',')
    values = [int(n) for n in numbers.split(',')]
    negatives = [n for n in values if n < 0]
    if negatives:
        raise ValueError(f'negatives not allowed: {", ".join(str(n) for n in negatives)}')
    return sum(values)
